struct Locked;
struct Unlocked;

struct Door<State> {
    _state: std::marker::PhantomData<State>,
}

impl Door<Locked> {
    fn unlock(self) -> Door<Unlocked> {
        Door { _state: std::marker::PhantomData }
    }
}

impl Door<Unlocked> {
    fn lock(self) -> Door<Locked> {
        Door { _state: std::marker::PhantomData }
    }
    fn open(&self) { println!(\"Door opened""); }
}
// door.open() only compiles on Door<Unlocked>"

Anti-Pattern:
enum DoorState { Locked, Unlocked }
struct Door { state: DoorState }
impl Door {
    fn open(&self) {
        match self.state {
            DoorState::Unlocked => println!(\"opened"")

