struct TempFile { path: std::path::PathBuf }

impl TempFile {
    fn new(path: impl Into<std::path::PathBuf>) -> std::io::Result<Self> {
        let path = path.into();
        std::fs::File::create(&path)?;
        Ok(Self { path })
    }
}

impl Drop for TempFile {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.path);
    }
}
// TempFile is automatically deleted when it goes out of scope

Anti-Pattern:
fn process() {
    let path = \"temp.txt"";
    std::fs::File::create(path).unwrap();
    // do work...
    // forgot to delete temp.txt
    // resource leak if function returns early
}"

