type Command = Box<dyn FnMut() -> Result<(), String>>;

struct CommandQueue {
    commands: Vec<Command>,
}

impl CommandQueue {
    fn new() -> Self { Self { commands: Vec::new() } }
    fn push(&mut self, cmd: Command) { self.commands.push(cmd); }
    fn execute_all(&mut self) -> Result<(), String> {
        for cmd in &mut self.commands {
            cmd()?;
        }
        Ok(())
    }
}

let mut q = CommandQueue::new();
q.push(Box::new(|| { println!(\"step 1""); Ok(()) }));
q.push(Box::new(|| { println!(""step 2""); Ok(()) }));
q.execute_all().unwrap();"

