use std::borrow::Cow;

fn normalize(input: &str) -> Cow<str> {
    if input.contains(' ') {
        Cow::Owned(input.replace(' ', \"_""))
    } else {
        Cow::Borrowed(input)
    }
}

// No allocation when input has no spaces
let result = normalize(""hello"");    // Cow::Borrowed
let result = normalize(""hello world""); // Cow::Owned"

Anti-Pattern:
fn normalize(input: &str) -> String {
    input.replace(' ', \"_"")
    // always allocates even when no spaces
}"

