use std::cell::RefCell;

struct Logger {
    messages: RefCell<Vec<String>>,
}

impl Logger {
    fn new() -> Self { Self { messages: RefCell::new(Vec::new()) } }
    fn log(&self, msg: &str) {
        self.messages.borrow_mut().push(msg.to_string());
    }
    fn dump(&self) -> Vec<String> {
        self.messages.borrow().clone()
    }
}

Anti-Pattern:
struct Logger {
    messages: Vec<String>,
}
// requires &mut self for log(), preventing shared references
// cannot use Logger behind Rc<Logger>

